const item = $input.first().json;

const firstName   = String(item['First Name']      ?? '').trim();
const lastName    = String(item['Last Name']       ?? '').trim();
const jobTitle    = String(item['Job Title']       ?? '').trim();
const studioRaw   = String(item['Studio']          ?? '').trim();
const empId       = String(item['EMP ID']          ?? '').trim();
const phoneExt    = String(item['Phone Extension'] ?? '').trim();
const credentials = String(item['Credentials']     ?? '').trim();

if (!firstName) throw new Error('First Name is required.');
if (!lastName)  throw new Error('Last Name is required.');
if (!studioRaw) throw new Error('Studio selection is required.');

// Auto-detect delimiter
const delimiter = studioRaw.includes(' ~~ ') ? ' ~~ ' : ' | ';
const parts     = studioRaw.split(delimiter).map(s => s.trim());
const labelPart = parts[0] ?? '';
const street    = parts[1] ?? '';
const state     = parts[3] ?? '';
const zip       = parts[4] ?? '';
const phone     = parts[5] ?? '';

const dashIdx = labelPart.indexOf(' — ');
const company = dashIdx !== -1 ? labelPart.substring(0, dashIdx).trim() : labelPart.trim();
const city    = dashIdx !== -1 ? labelPart.substring(dashIdx + 3).trim() : '';

if (!company) throw new Error(`Could not parse company from Studio value: ${studioRaw}`);
if (!city)    throw new Error(`Could not parse city from Studio value: ${studioRaw}`);

const ouCity = city.replace(/[-\s]/g, '');

const sAMAccountName     = (firstName.charAt(0) + lastName).toLowerCase();
const displayName        = `${firstName} ${lastName}`;
const cn                 = displayName;
const dn                 = `CN=${cn},OU=${ouCity},OU=${company},OU=MGA USERS,DC=MGA,DC=com`;
const targetOU           = `OU=${ouCity},OU=${company},OU=MGA USERS,DC=MGA,DC=com`;
const userPrincipalName  = `${sAMAccountName}@michaelgraves.com`;
const mail               = `${sAMAccountName}@michaelgraves.com`;

// Only include optional fields if they have a value
const optionalFields = {};
if (empId)       optionalFields.pager   = empId;
if (phoneExt)    optionalFields.ipPhone  = phoneExt;
if (credentials) optionalFields.info     = credentials;

return [{
  json: {
    dn,
    targetOU,
    sAMAccountName,
    displayName,
    givenName: firstName,
    sn: lastName,
    cn,
    title: jobTitle,
    company,
    streetAddress: street,
    l: city,
    st: state,
    postalCode: zip,
    telephoneNumber: phone,
    userPrincipalName,
    mail,
    objectClass: 'user',
    userAccountControl: '514',
    ...optionalFields
  }
}];

const adAttrs = $('Code: Build AD user attributes').first().json;
const searchResults = $input.all();

// alwaysOutputData=false on LDAP means 0 items = not found, 1+ items = found
// continueOnFail=true means errors also pass through as items with error info
const firstJson = searchResults.length > 0 ? searchResults[0].json : {};
const userExists = searchResults.length > 0 && !!firstJson.dn;

let existingDn = null;
let userAccountControl = null;
let isEnabled = false;

if (userExists) {
  existingDn = searchResults[0].json.dn || searchResults[0].json.distinguishedName || null;
  userAccountControl = parseInt(searchResults[0].json.userAccountControl ?? '514', 10);
  // UAC bit 2 (value 2) = account disabled
  isEnabled = (userAccountControl & 2) === 0;
}

console.log(`User exists: ${userExists}, DN: ${existingDn}, UAC: ${userAccountControl}, Enabled: ${isEnabled}`);

return [{
  json: {
    ...adAttrs,
    userExists,
    existingDn,
    userAccountControl: userAccountControl ?? 514,
    isEnabled
  }
}];

const adAttrs = $('Code: Build AD user attributes').first().json;
const existing = $('LDAP: Get current DN (enabled)').first().json;

function valueOrExisting(submitted, existingVal) {
  const v = String(submitted ?? '').trim();
  if (v !== '') return v;
  const e = String(existingVal ?? '').trim();
  return e !== '' ? e : ' ';
}

const finalTitle           = valueOrExisting(adAttrs.title, existing.title);
const finalCompany         = valueOrExisting(adAttrs.company, existing.company);
const finalStreetAddress   = valueOrExisting(adAttrs.streetAddress, existing.streetAddress);
const finalL               = valueOrExisting(adAttrs.l, existing.l);
const finalSt              = valueOrExisting(adAttrs.st, existing.st);
const finalPostalCode      = valueOrExisting(adAttrs.postalCode, existing.postalCode);
const finalTelephoneNumber = valueOrExisting(adAttrs.telephoneNumber, existing.telephoneNumber);
const finalMail            = valueOrExisting(adAttrs.mail, existing.mail);

const optionalFieldDefs = [
  { id: 'pager',   value: adAttrs.pager },
  { id: 'ipPhone', value: adAttrs.ipPhone },
  { id: 'info',    value: adAttrs.info },
];
const optionalReplace = optionalFieldDefs.filter(f => String(f.value ?? '').trim() !== '');
const hasOptional = optionalReplace.length > 0;

return [{
  json: {
    ...adAttrs,
    finalTitle, finalCompany, finalStreetAddress, finalL, finalSt,
    finalPostalCode, finalTelephoneNumber, finalMail,
    optionalReplace, hasOptional
  }
}];

