const adAttrs = $('Code: Build AD user attributes').first().json;

const plainPassword = `MGAtemp${new Date().getFullYear()}`;

function encodePassword(password) {
  let encoded = '';
  const quoted = '"' + password + '"';
  for (let i = 0; i < quoted.length; i++) {
    encoded += String.fromCharCode(
      quoted.charCodeAt(i) & 0xFF,
      (quoted.charCodeAt(i) >>> 8) & 0xFF
    );
  }
  return encoded;
}

return [{ json: { ...adAttrs, unicodePwd: encodePassword(plainPassword) } }];

